// src/App.js
import React, { useCallback, useEffect, useMemo } from "react";
import { useNodesState, useEdgesState } from "reactflow";
import { PipelineToolbar } from "./toolbar";
import { PipelineUI } from "./ui";
import FlowCanvas from "./FlowCanvas";

const INITIAL_NODES = [
  { id: "1", type: "inputNode", position: { x: 50, y: 50 }, data: { label: "Input" } },
  { id: "2", type: "llmNode", position: { x: 300, y: 50 }, data: { label: "LLM" } },
  { id: "3", type: "textNode", position: { x: 50, y: 200 }, data: { label: "Text" } },
  { id: "4", type: "outputNode", position: { x: 300, y: 200 }, data: { label: "Output" } },
  {
    id: "5",
    type: "deleteNode",
    position: { x: 550, y: 125 },
    data: { candidates: [], onDelete: () => {}, canDeleteTool: false },
  },
];

const INITIAL_EDGES = [
  { id: "e1-2", source: "1", target: "2" },
  { id: "e3-2", source: "3", target: "2" },
  { id: "e2-4", source: "2", target: "4" },
];

export default function App() {
  const [nodes, setNodes, onNodesChange] = useNodesState(INITIAL_NODES);
  const [edges, setEdges, onEdgesChange] = useEdgesState(INITIAL_EDGES);

  // central delete handler (uses functional updates to avoid stale closures)
  const handleDeleteNode = useCallback(
    (targetId) => {
      if (!targetId) return;

      // compute whether tool can be deleted now (no other nodes except "5")
      setNodes((prevNodes) => {
        const otherNodesCount = prevNodes.filter((n) => n.id !== "5").length;
        const canDeleteTool = otherNodesCount === 0;

        // guard: do not allow deleting the tool while other nodes exist
        if (targetId === "5" && !canDeleteTool) {
          window.alert(
            "Cannot delete the Delete Node tool while other nodes exist. Remove other nodes first."
          );
          return prevNodes;
        }

        // remove the target node
        return prevNodes.filter((n) => n.id !== targetId);
      });

      // remove edges connected to the target
      setEdges((prevEdges) => prevEdges.filter((e) => e.source !== targetId && e.target !== targetId));
    },
    [setNodes, setEdges]
  );

  // onConnect: add edge and update edges state
  const handleConnect = useCallback(
    (params) => {
      const newEdge = {
        id: params.id || `e${params.source}-${params.target}-${Date.now()}`,
        source: params.source,
        target: params.target,
        ...params,
      };
      setEdges((eds) => [...eds, newEdge]);
    },
    [setEdges]
  );

  // Build candidates list from current nodes (memoized)
  const deleteCandidates = useMemo(
    () =>
      nodes.map((n) => ({
        id: n.id,
        label: n.id === "5" ? "Delete Node (tool)" : n.data?.label || n.id,
      })),
    [nodes]
  );

  // Keep delete node's candidate list and canDeleteTool flag in sync with nodes
  useEffect(() => {
    setNodes((prevNodes) => {
      const idx = prevNodes.findIndex((n) => n.id === "5");
      if (idx === -1) return prevNodes;

      const deleteNode = prevNodes[idx];
      const otherNodesCount = prevNodes.filter((n) => n.id !== "5").length;
      const canDeleteTool = otherNodesCount === 0;

      const newData = {
        ...deleteNode.data,
        candidates: deleteCandidates,
        onDelete: handleDeleteNode,
        canDeleteTool,
      };

      // avoid unnecessary state updates by shallow-checking data equality
      const same =
        deleteNode.data &&
        deleteNode.data.candidates === newData.candidates &&
        deleteNode.data.canDeleteTool === newData.canDeleteTool &&
        deleteNode.data.onDelete === newData.onDelete;

      if (same) return prevNodes;

      const newNodes = [...prevNodes];
      newNodes[idx] = { ...deleteNode, data: newData };
      return newNodes;
    });
  }, [deleteCandidates, handleDeleteNode, setNodes]);

  return (
    <div style={{ height: "100vh", display: "flex", flexDirection: "column" }}>
      <PipelineToolbar />
      <PipelineUI />
      <FlowCanvas
        nodes={nodes}
        edges={edges}
        setNodes={setNodes} // pass setter so FlowCanvas can add nodes on drop
        onNodesChange={onNodesChange}
        onEdgesChange={onEdgesChange}
        onConnect={handleConnect}
      />
    </div>
  );
}
